            data[column_offset + (i + 1) * STRIDE] = in[col_loader_last];
        }
        if(x < 7) {
            for(int i = 7; i < (7 + WIN_SY); i += 2) {
                bound_loader_last += bound_loader_stride;
                if(bound_loader_last == bound_loader_end) { bound_loader_last -= 2 * bound_loader_stride; bound_loader_stride = -bound_loader_stride; }
                data[boundary_column_offset + i * STRIDE] = in[bound_loader_last];

                bound_loader_last += bound_loader_stride;
                if(bound_loader_last == bound_loader_end) { bound_loader_last -= 2 * bound_loader_stride; bound_loader_stride = -bound_loader_stride; }
                data[boundary_column_offset + (i + 1) * STRIDE] = in[bound_loader_last];
            }
        }

        int count = WIN_SY * STRIDE - 1;
        int STEPS = count / WIN_SX;
        int finalCount = count % WIN_SX;
        int finalOffset = count - finalCount;

        int offset = 7 * STRIDE;
        for(int i = 0; i < STEPS; i++) {
            data[x + i * WIN_SX + offset] *= scale97Mul;
            data[x + i * WIN_SX + offset + ODD_OFFSET] *= scale97Div;
        }
        if(x < finalCount) {
            data[x + finalOffset + offset] *= scale97Mul;
            data[x + finalOffset + offset + ODD_OFFSET] *= scale97Div;
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        int prevOffset = 7 * STRIDE + ODD_OFFSET;
        int centerOffset = 7 * STRIDE + 1;
        int nextOffset = prevOffset + 1;
        for(int i = 0; i < STEPS; i++) {
            float previous = data[prevOffset + i * WIN_SX + x];
            float next     = data[nextOffset + i * WIN_SX + x];
            float center = data[centerOffset  + i * WIN_SX + x];
            center += r97update2 * (previous + next);
            data[centerOffset  + i * WIN_SX + x] = center;
        }
        if(x < finalCount) {
            float previous = data[prevOffset + finalOffset + x];
            float next     = data[nextOffset + finalOffset + x];
            float center = data[centerOffset + finalOffset + x];
            center += r97update2 * (previous + next);
            data[centerOffset + finalOffset + x] = center;
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        prevOffset = 7 * STRIDE;
        centerOffset = prevOffset + ODD_OFFSET;
        nextOffset = prevOffset + 1;
        for(int i = 0; i < STEPS; i++) {
            float previous = data[prevOffset + i * WIN_SX + x];
            float next     = data[nextOffset + i * WIN_SX + x];
            float center = data[centerOffset  + i * WIN_SX + x];
            center += r97predict2 * (previous + next);
            data[centerOffset  + i * WIN_SX + x] = center;
        }
        if(x < finalCount) {
            float previous = data[prevOffset + finalOffset + x];
            float next     = data[nextOffset + finalOffset + x];
            float center = data[centerOffset + finalOffset + x];
            center += r97predict2 * (previous + next);
            data[centerOffset + finalOffset + x] = center;
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        prevOffset = 7 * STRIDE + ODD_OFFSET;
        centerOffset = 7 * STRIDE + 1;
        nextOffset = prevOffset + 1;
        for(int i = 0; i < STEPS; i++) {
            float previous = data[prevOffset + i * WIN_SX + x];
            float next     = data[nextOffset + i * WIN_SX + x];
            float center = data[centerOffset  + i * WIN_SX + x];
            center += r97update1 * (previous + next);
            data[centerOffset  + i * WIN_SX + x] = center;
        }
        if(x < finalCount) {
            float previous = data[prevOffset + finalOffset + x];
            float next     = data[nextOffset + finalOffset + x];
            float center = data[centerOffset + finalOffset + x];
            center += r97update1 * (previous + next);
            data[centerOffset + finalOffset + x] = center;
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        prevOffset = 7 * STRIDE;
        centerOffset = prevOffset + ODD_OFFSET;
        nextOffset = prevOffset + 1;
        for(int i = 0; i < STEPS; i++) {
            float previous = data[prevOffset + i * WIN_SX + x];
            float next     = data[nextOffset + i * WIN_SX + x];
            float center = data[centerOffset  + i * WIN_SX + x];
            center += r97Predict1 * (previous + next);
            data[centerOffset  + i * WIN_SX + x] = center;
        }
        if(x < finalCount) {
            float previous = data[prevOffset + finalOffset + x];
            float next     = data[nextOffset + finalOffset + x];
            float center = data[centerOffset + finalOffset + x];
            center += r97Predict1 * (previous + next);
            data[centerOffset + finalOffset + x] = center;
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        float last7Lines[7];
        for(int i = 0; i < 7; i++) {
            last7Lines[i] = data[outColumnOffset + (WIN_SY + i) * STRIDE];
        }

        for(int i = 0; i < (WIN_SY + 7); i++) {
            if(i & 1) {
                data[outColumnOffset + i * STRIDE] *= scale97Div;
            } else {
                data[outColumnOffset + i * STRIDE] *= scale97Mul;
            }
        }

        int steps_odd = (WIN_SY + 7 - 1) / 2;
        for(int i = 0; i < steps_odd; i++) {
            int row = i * 2 + 1;
            float prev = data[outColumnOffset + (row - 1) * STRIDE];
            float next = data[outColumnOffset + (row + 1) * STRIDE];
            float center = data[outColumnOffset + row * STRIDE];
            center += r97update2 * (prev + next);
            data[outColumnOffset + row * STRIDE] = center;
        }
        int steps_even = (WIN_SY + 7) / 2;
        for(int i = 0; i < steps_even; i++) {
            int row = i * 2;
            if(row == 0) continue;
            float prev = data[outColumnOffset + (row - 1) * STRIDE];
            float next = data[outColumnOffset + (row + 1) * STRIDE];
            float center = data[outColumnOffset + row * STRIDE];
            center += r97predict2 * (prev + next);
            data[outColumnOffset + row * STRIDE] = center;
        }
        steps_odd = (WIN_SY + 7 - 1) / 2;
        for(int i = 0; i < steps_odd; i++) {
            int row = i * 2 + 1;
            float prev = data[outColumnOffset + (row - 1) * STRIDE];
            float next = data[outColumnOffset + (row + 1) * STRIDE];
            float center = data[outColumnOffset + row * STRIDE];
            center += r97update1 * (prev + next);
            data[outColumnOffset + row * STRIDE] = center;
        }
        steps_even = (WIN_SY + 7) / 2;
        for(int i = 0; i < steps_even; i++) {
            int row = i * 2;
