            float prev = data[outColumnOffset + (row - 1) * STRIDE];
            float next = data[outColumnOffset + (row + 1) * STRIDE];
            float center = data[outColumnOffset + row * STRIDE];
            center += r97Predict1 * (prev + next);
            data[outColumnOffset + row * STRIDE] = center;
        }

        for(int i = 3; i < (3 + WIN_SY); i++) {
            if(writer_pos != writer_end) {
                out[writer_pos] = data[outColumnOffset + i * STRIDE];
                writer_pos += writer_stride;
            }
        }

        for(int i = 0; i < 7; i++) {
            data[outColumnOffset + i * STRIDE] = last7Lines[i];
